# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler: NSObject, UNUserNotificationCenterDelegate {
    static let shared = UniversalLinkHandler()
    
    private override init() {}
    
    func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else { return false }
        
        if isValidUniversalLink(url) {
            handlePasswordReset(url)
            return true
        }
        
        return false
    }
    
    private func isValidUniversalLink(_ url: URL) -> Bool {
        // Allowlist valid hosts and paths
        let allowedHosts = ["myapp.com"]
        let allowedPaths = ["/reset-password"]
        
        guard allowedHosts.contains(url.host ?? "") else { return false }
        guard allowedPaths.contains(url.path) else { return false }
        
        // Validate parameters (e.g., token)
        if url.queryItems?.contains(where: { $0.name == "token" && !($0.value?.isEmpty ?? true) }) == false {
            return false
        }
        
        return true
    }
    
    private func handlePasswordReset(_ url: URL) {
        guard let token = url.queryParameters["token"] else { return }
        
        // Navigate to the password reset screen with the token
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let sceneDelegate = windowScene.delegate as? SceneDelegate,
           let rootViewController = sceneDelegate.window?.rootViewController {
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            guard let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController else { return }
            
            passwordResetVC.resetToken = token
            rootViewController.present(passwordResetVC, animated: true, completion: nil)
        }
    }
}

extension URL {
    var queryParameters: [String: String] {
        guard let components = URLComponents(url: self, resolvingAgainstBaseURL: false), let queryItems = components.queryItems else { return [:] }
        
        var parameters = [String: String]()
        for item in queryItems {
            parameters[item.name] = item.value
        }
        
        return parameters
    }
